#!/usr/bin/env bash
# spawn-rknot-mesh.sh — bring up an N-station fat-station mesh against
# a single rknot + dense .knot pair.
#
# Each station holds a contiguous --layers window. All stations point
# at the same rknot/dense URLs. The TS coordinator (distributed-
# inference-host/src/station.ts) is responsible for fanning out
# /forward across them in order — this script does NOT start the
# coordinator, only the layer stations.
#
# Usage:
#   spawn-rknot-mesh.sh \
#     --rknot /path/llama-70b-precise.rknot \
#     --dense https://r2-proxy.../llama-70b.knot \
#     --total-layers 80 \
#     --stations 8 \
#     --start-port 8001 \
#     [--token-env-var R2_PROXY_TOKEN] \
#     [--ua-env-var KNOT_HTTP_USER_AGENT] \
#     [--bin /path/to/fat-station]
#
# Layer windows are computed by even split. For 80 layers / 8 stations
# you get [0,10) [10,20) ... [70,80). The first/last get role=entry/exit
# automatically; middle stations are role=mid.
#
# Pids are written to /tmp/fat-station-mesh-pids.<start_port> so the
# operator can kill the mesh in one shot:
#   xargs kill < /tmp/fat-station-mesh-pids.8001
#
# Disk: each station mmaps the rknot file. On Linux this shares pages
# across processes — N stations on the same host eat 1× rknot in RAM,
# not N×. On macOS the mmap behavior is the same but the page cache
# accounting is opaque. Cloud deploys typically run one station per
# instance so the dedup question doesn't matter.

set -eu

RKNOT=""
DENSE=""
TOTAL_LAYERS=80
STATIONS=8
START_PORT=8001
BIN=""
TOKEN_ENV=""
UA_ENV=""

while [ $# -gt 0 ]; do
  case "$1" in
    --rknot) RKNOT="$2"; shift 2 ;;
    --dense) DENSE="$2"; shift 2 ;;
    --total-layers) TOTAL_LAYERS="$2"; shift 2 ;;
    --stations) STATIONS="$2"; shift 2 ;;
    --start-port) START_PORT="$2"; shift 2 ;;
    --token-env-var) TOKEN_ENV="$2"; shift 2 ;;
    --ua-env-var) UA_ENV="$2"; shift 2 ;;
    --bin) BIN="$2"; shift 2 ;;
    -h|--help) sed -n '2,32p' "$0" | sed 's/^# *//'; exit 0 ;;
    *) echo "unknown arg: $1" >&2; exit 2 ;;
  esac
done

[ -z "$RKNOT" ] && { echo "ERROR: --rknot required" >&2; exit 2; }
[ -z "$DENSE" ] && { echo "ERROR: --dense required" >&2; exit 2; }
[ ! -f "$RKNOT" ] && { echo "ERROR: rknot not a file: $RKNOT" >&2; exit 2; }

if [ -z "$BIN" ]; then
  SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
  BIN="$SCRIPT_DIR/../target/release/fat-station"
fi
[ ! -x "$BIN" ] && { echo "ERROR: fat-station binary not found at $BIN" >&2; exit 2; }

# Ceil-div: round up so the last station picks up any remainder.
LAYERS_PER=$(( (TOTAL_LAYERS + STATIONS - 1) / STATIONS ))
PID_FILE="/tmp/fat-station-mesh-pids.${START_PORT}"
: > "$PID_FILE"

echo "spawn-rknot-mesh: ${STATIONS} stations × ${LAYERS_PER} layers (covering ${TOTAL_LAYERS} layers)"
echo "  rknot:  $RKNOT"
echo "  dense:  $DENSE"
echo "  ports:  ${START_PORT}..$((START_PORT + STATIONS - 1))"
echo "  pids → $PID_FILE"
echo

for i in $(seq 0 $((STATIONS - 1))); do
  start=$((i * LAYERS_PER))
  end=$((start + LAYERS_PER))
  [ $end -gt $TOTAL_LAYERS ] && end=$TOTAL_LAYERS
  port=$((START_PORT + i))
  if [ $i -eq 0 ]; then role="entry"
  elif [ $i -eq $((STATIONS - 1)) ]; then role="exit"
  else role="mid"
  fi
  echo "  [station $i] layers=${start}..${end} role=${role} port=${port}"

  # Build env prefix conditionally (don't override if vars unset)
  env_prefix=""
  [ -n "$TOKEN_ENV" ] && env_prefix="$env_prefix $TOKEN_ENV=\"\${$TOKEN_ENV:-}\""
  [ -n "$UA_ENV" ] && env_prefix="$env_prefix $UA_ENV=\"\${$UA_ENV:-}\""

  eval $env_prefix "$BIN" \
    --rknot "$RKNOT" \
    --dense "$DENSE" \
    --layers "${start}..${end}" \
    --role "$role" \
    --port "$port" \
    --no-standing-wave \
    > "/tmp/fat-station-${port}.log" 2>&1 &

  echo "$!" >> "$PID_FILE"
done

echo
echo "spawn-rknot-mesh: ${STATIONS} stations launched"
echo "  follow logs: tail -F /tmp/fat-station-*.log"
echo "  poll health: for p in \$(seq ${START_PORT} $((START_PORT + STATIONS - 1))); do curl -s http://localhost:\$p/health | head -c 100; echo; done"
echo "  kill mesh:   xargs kill < $PID_FILE"
